 16→package com.ichi2.anki.preferences
 17→
 18→import android.content.ComponentName
 19→import android.content.Context
 20→import android.content.Intent
 21→import android.content.pm.PackageManager
 22→import androidx.appcompat.app.AlertDialog
 23→import androidx.preference.EditTextPreference
 24→import androidx.preference.Preference
 25→import androidx.preference.SwitchPreferenceCompat
 26→import com.ichi2.anki.AnkiActivity
 27→import com.ichi2.anki.CollectionHelper
 28→import com.ichi2.anki.MetaDB
 29→import com.ichi2.anki.R
 30→import com.ichi2.anki.exception.StorageAccessException
 31→import com.ichi2.anki.provider.CardContentProvider
 32→import com.ichi2.anki.snackbar.showSnackbar
 33→import com.ichi2.compat.CompatHelper
 34→import com.ichi2.utils.show
 35→import timber.log.Timber
 36→
 37→class AdvancedSettingsFragment : SettingsFragment() {
 38→    override val preferenceResource: Int
 39→        get() = R.xml.preferences_advanced
 40→    override val analyticsScreenNameConstant: String
 41→        get() = "prefs.advanced"
 42→
 43→    override fun initSubscreen() {
 44→        removeUnnecessaryAdvancedPrefs()
 45→
 46→        // Check that input is valid before committing change in the collection path
 47→        requirePreference<EditTextPreference>(CollectionHelper.PREF_COLLECTION_PATH).apply {
 48→            setOnPreferenceChangeListener { _, newValue: Any? ->
 49→                val newPath = newValue as String
 50→                try {
 51→                    CollectionHelper.initializeAnkiDroidDirectory(newPath)
 52→                    (requireActivity() as Preferences).restartWithNewDeckPicker()
 53→                    true
 54→                } catch (e: StorageAccessException) {
 55→                    // TODO: Request MANAGE_EXTERNAL_STORAGE
 56→                    Timber.e(e, "Could not initialize directory: %s", newPath)
 57→                    AlertDialog.Builder(requireContext()).show {
 58→                        setTitle(R.string.dialog_collection_path_not_dir)
 59→                        setPositiveButton(R.string.dialog_ok) { _, _ -> }
 60→                        setNegativeButton(R.string.reset_custom_buttons) { _, _ ->
 61→                            text = CollectionHelper.getDefaultAnkiDroidDirectory(requireContext())
 62→                        }
 63→                    }
 64→                    false
 65→                }
 66→            }
 67→        }
 68→
 69→        val ttsPref = requirePreference<SwitchPreferenceCompat>(R.string.tts_key)
 70→        ttsPref.setOnPreferenceChangeListener { _, isChecked ->
 71→            if (!(isChecked as Boolean)) return@setOnPreferenceChangeListener true
 72→            AlertDialog.Builder(requireContext()).show {
 73→                setIcon(R.drawable.ic_warning)
 74→                setMessage(R.string.readtext_deprecation_warn)
 75→                setNegativeButton(R.string.dialog_cancel) { _, _ -> ttsPref.isChecked = false }
 76→                setNeutralButton(R.string.scoped_storage_learn_more) { _, _ ->
 77→                    ttsPref.isChecked = false
 78→                    (requireActivity() as AnkiActivity).openUrl(R.string.link_tts)
 79→                }
 80→                setPositiveButton(R.string.dialog_ok) { _, _ -> }
 81→                setOnCancelListener { ttsPref.isChecked = false }
 82→            }
 83→            return@setOnPreferenceChangeListener true
 84→        }
 85→
 86→        // Configure "Reset languages" preference
 87→        requirePreference<Preference>(R.string.pref_reset_languages_key).setOnPreferenceClickListener {
 88→            AlertDialog.Builder(requireContext()).show {
 89→                setTitle(R.string.reset_languages)
 90→                setIcon(R.drawable.ic_warning)
 91→                setMessage(R.string.reset_languages_question)
 92→                setPositiveButton(R.string.dialog_ok) { _, _ ->
 93→                    if (MetaDB.resetLanguages(requireContext())) {
 94→                        showSnackbar(R.string.reset_confirmation)
 95→                    }
 96→                }
 97→                setNegativeButton(R.string.dialog_cancel) { _, _ -> }
 98→            }
 99→            false
100→        }
101→
102→        /*
103→         * Plugins section
104→         */
105→
106→        // Third party apps
107→        requirePreference<Preference>(R.string.thirdparty_apps_key).setOnPreferenceClickListener {
108→            (requireActivity() as AnkiActivity).openUrl(R.string.link_third_party_api_apps)
109→            false
110→        }
111→
112→        // Enable API
113→        requirePreference<SwitchPreferenceCompat>(R.string.enable_api_key).setOnPreferenceChangeListener { newValue ->
114→            val providerName = ComponentName(requireContext(), CardContentProvider::class.java.name)
115→            val state = if (newValue == true) {
116→                Timber.i("AnkiDroid ContentProvider enabled by user")
117→                PackageManager.COMPONENT_ENABLED_STATE_ENABLED
118→            } else {
119→                Timber.i("AnkiDroid ContentProvider disabled by user")
120→                PackageManager.COMPONENT_ENABLED_STATE_DISABLED
121→            }
122→            requireActivity().packageManager.setComponentEnabledSetting(providerName, state, PackageManager.DONT_KILL_APP)
123→        }
124→    }
125→
126→    private fun removeUnnecessaryAdvancedPrefs() {
127→        /** These preferences should be searchable or not based
128→         * on this same condition at [Preferences.configureSearchBar] */
129→        // Disable the double scroll preference if no scrolling keys
130→        if (!CompatHelper.hasScrollKeys()) {
131→            val doubleScrolling = findPreference<SwitchPreferenceCompat>("double_scrolling")
132→            if (doubleScrolling != null) {
133→                preferenceScreen.removePreference(doubleScrolling)
134→            }
135→        }
136→    }
137→
138→    companion object {
139→        fun getSubscreenIntent(context: Context): Intent {
140→            return getSubscreenIntent(context, AdvancedSettingsFragment::class)
141→        }
142→    }
143→}
