 81→     *          return withContext(collectionOperationsDispatcher) {
 82→     *              block(queue)
 83→     *          }
 84→     *      }
 85→     *
 86→     *   Then, only functions that are also marked can be run inside the block:
 87→     *
 88→     *       context(Queue) suspend fun canOnlyBeRunInWithQueue()
 89→     */
 90→    private suspend fun<T> withQueue(@WorkerThread block: CollectionManager.() -> T): T {
 91→        if (isRobolectric) {
 92→            // #16253 Robolectric Windows: `withContext(queue)` is insufficient for serial execution
 93→            return testMutex.withLock {
 94→                this@CollectionManager.block()
 95→            }
 96→        }
 97→        return withContext(queue) {
 98→            this@CollectionManager.block()
 99→        }
100→    }
101→
102→    /**
103→     * Execute the provided block with the collection, opening if necessary.
104→     *
105→     * Calls are serialized, and run in background [Dispatchers.IO] thread.
106→     *
107→     * Parallel calls to this function are guaranteed to be serialized, so you can be
108→     * sure the collection won't be closed or modified by another thread. This guarantee
109→     * does not hold if legacy code calls [getColUnsafe].
110→     */
111→    suspend fun <T> withCol(@WorkerThread block: Collection.() -> T): T {
112→        return withQueue {
113→            ensureOpenInner()
114→            block(collection!!)
115→        }
116→    }
117→
118→    /**
119→     * Execute the provided block if the collection is already open. See [withCol] for more.
120→     * Since the block may return a null value, and a null value will also be returned in the
121→     * case of the collection being closed, if the calling code needs to distinguish between
122→     * these two cases, it should wrap the return value of the block in a class (eg Optional),
123→     * instead of returning a nullable object.
124→     */
125→    suspend fun<T> withOpenColOrNull(@WorkerThread block: Collection.() -> T): T? {
126→        return withQueue {
127→            if (collection != null && !collection!!.dbClosed) {
128→                block(collection!!)
129→            } else {
130→                null
131→            }
132→        }
133→    }
134→
135→    /**
136→     * Return a handle to the backend, creating if necessary. This should only be used
137→     * for routines that don't depend on an open or closed collection, such as checking
138→     * the current progress state when importing a colpkg file. While the backend is
139→     * thread safe and can be accessed concurrently, if another thread closes the collection
140→     * and you call a routine that expects an open collection, it will result in an error.
141→     */
142→    fun getBackend(): Backend {
143→        if (backend == null) {
144→            runBlocking { withQueue { ensureBackendInner() } }
145→        }
146→        return backend!!
147→    }
148→
149→    /**
150→     * Translations provided by the Rust backend/Anki desktop code.
151→     */
152→    val TR: Translations
153→        get() {
154→            // we bypass the lock here so that translations are fast - conflicts are unlikely,
155→            // as the backend is only ever changed on language preference change or schema switch
156→            return getBackend().tr
157→        }
158→
159→    fun compareAnswer(expected: String, given: String): String {
160→        // bypass the lock, as the type answer code is heavily nested in non-suspend functions
161→        return getBackend().compareAnswer(expected, given)
162→    }
163→
164→    /**
165→     * Close the currently cached backend and discard it. Useful when enabling the V16 scheduler in the
166→     * dev preferences, or if the active language changes. Saves and closes the collection if open.
167→     */
168→    suspend fun discardBackend() {
169→        withQueue {
170→            discardBackendInner()
171→        }
172→    }
173→
174→    /** See [discardBackend]. This must only be run inside the queue. */
175→    private fun discardBackendInner() {
176→        ensureClosedInner()
177→        if (backend != null) {
178→            backend!!.close()
179→            backend = null
180→        }
181→    }
182→
183→    /**
184→     * Open the backend if it's not already open.
185→     */
186→    private suspend fun ensureBackend() {
187→        withQueue {
188→            ensureBackendInner()
189→        }
190→    }
191→
192→    /** See [ensureBackend]. This must only be run inside the queue. */
193→    private fun ensureBackendInner() {
194→        if (backend == null) {
195→            backend = BackendFactory.getBackend()
196→        }
197→    }
198→
199→    /**
200→     * If the collection is open, close it.
201→     */
202→    suspend fun ensureClosed() {
203→        withQueue {
204→            ensureClosedInner()
205→        }
206→    }
207→
208→    /** See [ensureClosed]. This must only be run inside the queue. */
209→    private fun ensureClosedInner() {
210→        if (collection == null) {
211→            return
212→        }
213→        try {
214→            collection!!.close()
215→        } catch (exc: Exception) {
216→            Timber.e("swallowing error on close: $exc")
217→        }
218→        collection = null
219→    }
220→
221→    /**
222→     * Open the collection, if it's not already open.
223→     *
224→     * Automatically called by [withCol]. Can be called directly to ensure collection
225→     * is loaded at a certain point in time, or to ensure no errors occur.
226→     */
227→    private suspend fun ensureOpen() {
228→        withQueue {
229→            ensureOpenInner()
230→        }
231→    }
232→
233→    /** See [ensureOpen]. This must only be run inside the queue. */
234→    private fun ensureOpenInner() {
235→        ensureBackendInner()
236→        if (emulateOpenFailure) {
237→            throw BackendException.BackendDbException.BackendDbLockedException(backendError {})
238→        }
239→        if (collection == null || collection!!.dbClosed) {
240→            val path = collectionPathInValidFolder()
241→            collection =
242→                collection(path, backend)
243→        }
244→    }
245→
246→    suspend fun deleteCollectionDirectory() {
247→        withQueue {
248→            ensureClosedInner()
249→            getCollectionDirectory().deleteRecursively()
250→        }
251→    }
252→
253→    fun getCollectionDirectory() =
254→        // Allow execution if AnkiDroidApp.instance is not initialized
255→        File(CollectionHelper.getCurrentAnkiDroidDirectoryOptionalContext(AnkiDroidApp.sharedPrefs()) { AnkiDroidApp.instance })
256→
257→    /** Ensures the AnkiDroid directory is created, then returns the path to the collection file
258→     * inside it. */
259→    fun collectionPathInValidFolder(): String {
260→        val dir = getCollectionDirectory().path
261→        CollectionHelper.initializeAnkiDroidDirectory(dir)
262→        return File(dir, "collection.anki2").absolutePath
263→    }
264→
265→    /**
266→     * Like [withQueue], but can be used in a synchronous context.
267→     *
268→     * Note: [runBlocking] inside `RobolectricTest.runTest` will lead to deadlocks, so
269→     * under Robolectric, this uses a mutex
270→     */
271→    private fun <T> blockForQueue(block: CollectionManager.() -> T): T {
272→        return if (isRobolectric) {
273→            testMutex.withLock {
274→                block(this)
275→            }
276→        } else {
277→            runBlocking {
278→                withQueue(block)
279→            }
280→        }
281→    }
282→
283→    fun closeCollectionBlocking() {
284→        runBlocking { ensureClosed() }
285→    }
286→
287→    /**
288→     * Returns a reference to the open collection. This is not
289→     * safe, as code in other threads could open or close
290→     * the collection while the reference is held. [withCol]
291→     * is a better alternative.
292→     */
293→    fun getColUnsafe(): Collection {
294→        return logUIHangs {
295→            blockForQueue {
296→                ensureOpenInner()
297→                collection!!
298→            }
299→        }
300→    }
301→
302→    /**
303→     Execute [block]. If it takes more than 100ms of real time, Timber an error like:
304→     > Blocked main thread for 2424ms: com.ichi2.anki.DeckPicker.onCreateOptionsMenu(DeckPicker.kt:624)
305→     */
306→    // using TimeManager breaks a sched test that makes assumptions about the time, so we
307→    // access the time directly
308→    @SuppressLint("DirectSystemCurrentTimeMillisUsage")
309→    private fun <T> logUIHangs(block: () -> T): T {
310→        val start = System.currentTimeMillis()
311→        return block().also {
312→            val elapsed = System.currentTimeMillis() - start
313→            if (Threads.isOnMainThread && elapsed > 100) {
314→                val stackTraceElements = Thread.currentThread().stackTrace
315→                // locate the probable calling file/line in the stack trace, by filtering
316→                // out our own code, and standard dalvik/java.lang stack frames
317→                val caller = stackTraceElements.filter {
318→                    val klass = it.className
319→                    val toCheck = listOf(
320→                        "CollectionManager",
321→                        "dalvik",
322→                        "java.lang",
323→                        "CollectionHelper",
324→                        "AnkiActivity"
325→                    )
326→                    for (text in toCheck) {
327→                        if (text in klass) {
328→                            return@filter false
329→                        }
330→                    }
331→                    true
332→                }.first()
333→                Timber.w("blocked main thread for %dms:\n%s", elapsed, caller)
334→            }
335→        }
336→    }
337→
338→    /**
339→     * True if the collection is open. Unsafe, as it has the potential to race.
340→     */
341→    fun isOpenUnsafe(): Boolean {
342→        return logUIHangs {
343→            blockForQueue {
344→                if (emulateOpenFailure) {
345→                    false
346→                } else {
347→                    collection?.dbClosed == false
348→                }
349→            }
350→        }
351→    }
352→
353→    /**
354→     Use [col] as collection in tests.
355→     This collection persists only up to the next (direct or indirect) call to `ensureClosed`
356→     */
357→    fun setColForTests(col: Collection?) {
358→        blockForQueue {
359→            if (col == null) {
360→                ensureClosedInner()
361→            }
362→            collection = col
363→        }
364→    }
365→
366→    /**
367→     * Replace the collection with the provided colpkg file if it is valid.
368→     */
369→    suspend fun importColpkg(colpkgPath: String) {
370→        withQueue {
371→            ensureClosedInner()
372→            ensureBackendInner()
373→            importCollectionPackage(backend!!, collectionPathInValidFolder(), colpkgPath)
374→        }
375→    }
376→
377→    fun setTestDispatcher(dispatcher: CoroutineDispatcher) {
378→        // note: we avoid the call to .limitedParallelism() here,
379→        // as it does not seem to be compatible with the test scheduler
380→        queue = dispatcher
381→    }
382→
383→    /**
384→     * Update the custom TLS certificate used in the backend for its requests to the sync server.
385→     *
386→     * If the cert parameter hasn't changed from the cached sync certificate, then just return true.
387→     * Otherwise, set the custom certificate in the backend and get the success value.
388→     *
389→     * If cert was a valid certificate, then cache it in currentSyncCertificate and return true.
390→     * Otherwise, return false to indicate that a custom sync certificate was not applied.
391→     *
392→     * Passing in an empty string unsets any custom sync certificate in the backend.
393→     */
394→    fun updateCustomCertificate(cert: String): Boolean {
395→        if (cert == currentSyncCertificate) {
396→            return true
397→        }
398→
399→        return getBackend().setCustomCertificate(cert).apply {
400→            if (this) {
401→                currentSyncCertificate = cert
402→            }
403→        }
404→    }
405→}
